function findOddEventSubArray_2(array) {
    let oddCount = 0
      , eventCount = 0
      , count = 0;

    for (let i of array) {
        if (i % 2 === 0) {
            eventCount++
        } else {
            oddCount++
        }

        if (oddCount >= 1 && eventCount >= 1) {
            count++;
            eventCount = 0;
            oddCount = 0;
        }

    }

    return count; 
}

